import {eventBus, EventType, Handler} from "./eventBus";
import {MainScenariosEventMap, MicroScenariosEventMap} from "./event/acp";

export class AppSystemCommProtocol<Scenario extends (keyof typeof MainScenariosEventMap) | (keyof typeof MicroScenariosEventMap) = any, ScenarioHandlerMap extends Map<Scenario, Handler> = any> {
    protected readonly scenarioHandlerMap: ScenarioHandlerMap
    protected readonly appName: string
    protected readonly eventBus = eventBus

    constructor(appName: string, acpScenarioHandlerMapFromProps: ScenarioHandlerMap) {
        this.appName = appName ?? ''
        this.scenarioHandlerMap = acpScenarioHandlerMapFromProps
        this.scenarioHandlerMap.forEach((_handler,scenario )=>{
            eventBus.on(scenario as EventType, payload => {
                this.scenarioHandlerMap.get(scenario)!(payload)
            })
        })
    }

    destroy() {
        Object.keys(this.scenarioHandlerMap).forEach((scenario) => {
            this.eventBus.all.delete(scenario)
        })
    }
}
